        issues.push(`Task "${task.id}" resourceCost exceeds totalResources`)
      }
      if (task.durationMs <= 0) {
        issues.push(`Task "${task.id}" durationMs must be > 0`)
      }
      if (task.dependencies.includes(task.id)) {
        issues.push(`Task "${task.id}" has self-dependency`)
      }
      task.dependencies.forEach((depId) => {
        if (!tasks.has(depId)) {
          issues.push(`Task "${task.id}" depends on non-existent task "${depId}"`)
        }
      })
    })

    return issues
  }

  const detectCycle = (): string[] | null => {
    const visited = new Set<string>()
    const recStack = new Set<string>()
    const path: string[] = []

    const dfs = (nodeId: string): string[] | null => {
      visited.add(nodeId)
      recStack.add(nodeId)
      path.push(nodeId)

      const task = tasks.get(nodeId)
      if (!task) return null

      for (const depId of task.dependencies) {
        if (!visited.has(depId)) {
          const cycle = dfs(depId)
          if (cycle) return cycle
        } else if (recStack.has(depId)) {
          const cycleStart = path.indexOf(depId)
          const cycle = path.slice(cycleStart)
          cycle.push(depId)
          return cycle
        }
      }

      path.pop()
      recStack.delete(nodeId)
      return null
    }

    for (const taskId of tasks.keys()) {
      if (!visited.has(taskId)) {
        const cycle = dfs(taskId)
        if (cycle) return cycle
      }
    }

    return null
  }

  const schedule = (): ScheduleResult => {
    const cycle = detectCycle()
    if (cycle) {
      throw new SchedulerError(`Cycle detected: ${cycle.join(" -> ")}`)
    }

    const entries: ScheduleEntry[] = []
    const scheduled = new Set<string>()
    const running = new Map<string, { endTime: number; resourceCost: number }>()
    let currentTime = 0
    const roundsSkippedWhileReady = new Map<string, number>()

    let maxPriority = 0
    for (const task of tasks.values()) {
      maxPriority = Math.max(maxPriority, task.priority)
    }

    const isReady = (taskId: string): boolean => {
      const task = tasks.get(taskId)
      if (!task || scheduled.has(taskId)) return false
      return task.dependencies.every((depId) => scheduled.has(depId))
    }

    while (scheduled.size < tasks.size) {
      const ready = Array.from(tasks.keys()).filter((id) => isReady(id))

      if (ready.length === 0) {
        if (running.size === 0) break

        let minEndTime = Infinity
        for (const { endTime } of running.values()) {
          minEndTime = Math.min(minEndTime, endTime)
        }
        currentTime = minEndTime

        for (const [taskId, { endTime }] of running.entries()) {
          if (endTime === currentTime) {
            running.delete(taskId)
            roundsSkippedWhileReady.delete(taskId)
          }
        }
        continue
      }

      const readyWithPriority = ready.map((taskId) => {
        const skipped = roundsSkippedWhileReady.get(taskId) || 0
        const boostedPriority =
          skipped >= 3 ? maxPriority + 1 : tasks.get(taskId)!.priority
        return { taskId, priority: boostedPriority }
      })

      readyWithPriority.sort((a, b) => {
        if (a.priority !== b.priority) return b.priority - a.priority
        return a.taskId.localeCompare(b.taskId)
      })

      let scheduledAny = false
      const usedResources = Array.from(running.values()).reduce(
        (sum, r) => sum + r.resourceCost,
        0
      )

      for (const { taskId } of readyWithPriority) {
        const task = tasks.get(taskId)!
        const availableResources = config.totalResources - usedResources
        const runningCount = running.size

        if (
          runningCount < config.maxConcurrency &&
          task.resourceCost <= availableResources
        ) {
          const startTime = currentTime
          const endTime = currentTime + task.durationMs
          entries.push({
            taskId,
            startTime,
            endTime,
            resourcesUsed: task.resourceCost,
          })
          scheduled.add(taskId)
          running.set(taskId, { endTime, resourceCost: task.resourceCost })
          roundsSkippedWhileReady.delete(taskId)
          scheduledAny = true
        } else {
          roundsSkippedWhileReady.set(
            taskId,
            (roundsSkippedWhileReady.get(taskId) || 0) + 1
          )
        }
      }

      if (!scheduledAny && running.size > 0) {
        let minEndTime = Infinity
        for (const { endTime } of running.values()) {
          minEndTime = Math.min(minEndTime, endTime)
        }
        currentTime = minEndTime

        for (const [taskId, { endTime }] of running.entries()) {
          if (endTime === currentTime) {
            running.delete(taskId)
            roundsSkippedWhileReady.delete(taskId)
          }
        }
      }
    }

    let makespan = 0
    for (const entry of entries) {
      makespan = Math.max(makespan, entry.endTime)
    }

    const sortedEntries = [...entries].sort((a, b) => {
      if (a.startTime !== b.startTime) return a.startTime - b.startTime
      const taskA = tasks.get(a.taskId)!
      const taskB = tasks.get(b.taskId)!
      if (taskA.priority !== taskB.priority) return taskB.priority - taskA.priority
      return a.taskId.localeCompare(b.taskId)
    })

    const order = sortedEntries.map((e) => e.taskId)

    return { entries, makespan, order }
  }

  const criticalPath = (): string[] => {
    const memo = new Map<string, { path: string[]; length: number }>()

    const computePath = (taskId: string): { path: string[]; length: number } => {
      if (memo.has(taskId)) {
        return memo.get(taskId)!
      }

      const task = tasks.get(taskId)!

      if (task.dependencies.length === 0) {
        const result = { path: [taskId], length: task.durationMs }
        memo.set(taskId, result)
        return result
      }

      let maxLength = task.durationMs
      let maxPath = [taskId]

      for (const depId of task.dependencies) {
        const depPath = computePath(depId)
        const totalLength = depPath.length + task.durationMs

        if (totalLength > maxLength) {
          maxLength = totalLength
          maxPath = [...depPath.path, taskId]
        } else if (totalLength === maxLength) {
          const newPath = [...depPath.path, taskId]
          const minLen = Math.min(newPath.length, maxPath.length)
          let useNew = false
          for (let i = 0; i < minLen; i++) {
            if (newPath[i] !== maxPath[i]) {
              const newPriority = tasks.get(newPath[i])?.priority ?? 0
              const maxPriorityVal = tasks.get(maxPath[i])?.priority ?? 0
              if (newPriority > maxPriorityVal) {
                useNew = true
              } else if (newPriority === maxPriorityVal) {
                useNew = newPath[i] < maxPath[i]
              }
              break
            }
          }
          if (useNew) {
            maxPath = newPath
          }
        }
      }

      const result = { path: maxPath, length: maxLength }
      memo.set(taskId, result)
      return result
    }

    let longestPath: string[] = []
    let longestLength = 0

    for (const taskId of tasks.keys()) {
      const { path, length } = computePath(taskId)
      if (length > longestLength) {
        longestLength = length
        longestPath = path
      } else if (length === longestLength && longestPath.length === 0) {
        longestPath = path
      }
    }

    return longestPath
  }

  const topologicalOrder = (): string[] => {
    const inDegree = new Map<string, number>()
    const adjList = new Map<string, string[]>()

    for (const taskId of tasks.keys()) {
      inDegree.set(taskId, 0)
      adjList.set(taskId, [])
    }

    for (const task of tasks.values()) {
      for (const depId of task.dependencies) {
        const curr = inDegree.get(task.id) || 0
        inDegree.set(task.id, curr + 1)
        const adj = adjList.get(depId) || []
        adj.push(task.id)
        adjList.set(depId, adj)
      }
    }

    const queue = Array.from(tasks.keys()).filter((id) => inDegree.get(id) === 0)
    const result: string[] = []

    while (queue.length > 0) {
      queue.sort((a, b) => {
        const taskA = tasks.get(a)!
        const taskB = tasks.get(b)!
        if (taskA.priority !== taskB.priority) {
          return taskB.priority - taskA.priority
        }
        return a.localeCompare(b)
      })

      const taskId = queue.shift()!
      result.push(taskId)

      const neighbors = adjList.get(taskId) || []
      for (const neighborId of neighbors) {
        const newInDegree = (inDegree.get(neighborId) || 0) - 1
        inDegree.set(neighborId, newInDegree)
        if (newInDegree === 0) {
          queue.push(neighborId)
        }
      }
    }

    return result
  }

  return {
    addTask,
    validate,
    detectCycle,
    schedule,
    criticalPath,
    topologicalOrder,
  }
}
